"use client";

import { cn } from "@/lib/utils";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { TokenLogo, type TokenLogoProps } from "./token-logo";
import type { ReactNode } from "react";

export interface TokenStackItem
  extends Pick<
    TokenLogoProps,
    "address" | "chainId" | "fallback" | "name" | "src" | "symbol"
  > {
  id?: string;
}

export interface TokenStackProps {
  /** Tokens to display in the stack */
  tokens: TokenStackItem[];
  /** Maximum visible tokens before overflow. Default: 5 */
  limit?: number;
  /** Token logo size. Default: md */
  size?: TokenLogoProps["size"];
  /** Overlap direction. Default: left */
  direction?: "left" | "right";
  /** Show overflow count when tokens exceed limit. Default: true */
  showOverflow?: boolean;
  /** Custom overflow renderer */
  renderOverflow?: (count: number) => ReactNode;
  /** Custom token renderer for icon libraries or chain overlays */
  renderToken?: (token: TokenStackItem, index: number) => ReactNode;
  /** Show animated tooltips for tokens. Default: false */
  showTooltip?: boolean;
  /** Token tooltip content. Defaults to name, symbol, then address. */
  getTooltipContent?: (token: TokenStackItem, index: number) => ReactNode;
  /** Overflow tooltip content. Defaults to hidden token symbols/names. */
  getOverflowTooltipContent?: (tokens: TokenStackItem[]) => ReactNode;
  /** Accessible label for the group */
  "aria-label"?: string;
  /** Applied to the root wrapper */
  className?: string;
  /** Applied to each token wrapper */
  itemClassName?: string;
  /** Applied to the overflow item */
  overflowClassName?: string;
}

const overlapClasses = {
  left: "-space-x-2",
  right: "space-x-reverse -space-x-2",
} as const;

const overflowSizeClasses = {
  xs: "size-5 text-[9px]",
  sm: "size-6 text-[10px]",
  md: "size-8 text-xs",
  lg: "size-10 text-sm",
  xl: "size-12 text-base",
} as const;

function getTokenKey(token: TokenStackItem, index: number) {
  // Index-suffixed so the same token can legitimately appear twice, e.g. in
  // swap routes.
  return `${token.id ?? token.address ?? token.symbol ?? token.name ?? "token"}:${index}`;
}

export function TokenStack({
  tokens,
  limit = 5,
  size = "md",
  direction = "left",
  showOverflow = true,
  renderOverflow,
  renderToken,
  showTooltip = false,
  getTooltipContent,
  getOverflowTooltipContent,
  "aria-label": ariaLabel = "Token stack",
  className,
  itemClassName,
  overflowClassName,
}: TokenStackProps) {
  const visibleTokens = tokens.slice(0, limit);
  const hiddenTokens = tokens.slice(limit);
  const overflowCount = Math.max(tokens.length - visibleTokens.length, 0);

  const getDefaultTooltipContent = (token: TokenStackItem) =>
    token.name ?? token.symbol ?? token.address;

  const getDefaultOverflowTooltipContent = () => (
    <div className="flex flex-col gap-1">
      {hiddenTokens.map((token, index) => (
        <span key={getTokenKey(token, index)}>
          {token.symbol ?? token.name ?? token.address}
        </span>
      ))}
    </div>
  );

  return (
    <div
      className={cn("flex items-center", overlapClasses[direction], className)}
      aria-label={ariaLabel}
      role="list"
    >
      {visibleTokens.map((token, index) => {
        const item = (
          <span
            key={getTokenKey(token, index)}
            className={cn(
              "relative inline-flex rounded-full ring-2 ring-background/70",
              "hover:z-10",
              itemClassName
            )}
            title={!showTooltip ? token.name ?? token.symbol ?? undefined : undefined}
            role="listitem"
            style={{
              zIndex:
                direction === "left" ? visibleTokens.length - index : index + 1,
            }}
          >
            {renderToken ? (
              renderToken(token, index)
            ) : (
              <TokenLogo
                address={token.address}
                chainId={token.chainId}
                fallback={token.fallback}
                name={token.name}
                size={size}
                src={token.src}
                symbol={token.symbol}
              />
            )}
          </span>
        );

        if (!showTooltip) return item;

        return (
          <Tooltip key={getTokenKey(token, index)}>
            <TooltipTrigger render={item} />
            <TooltipContent>
              {getTooltipContent
                ? getTooltipContent(token, index)
                : getDefaultTooltipContent(token)}
            </TooltipContent>
          </Tooltip>
        );
      })}

      {showOverflow && overflowCount > 0 && (() => {
        const overflowItem = (
          <span
            className={cn(
              "relative inline-flex shrink-0 items-center justify-center rounded-full border bg-muted font-medium text-muted-foreground ring-2 ring-background/70",
              overflowSizeClasses[size],
              overflowClassName
            )}
            aria-label={`${overflowCount} more tokens`}
            role="listitem"
          >
            {renderOverflow ? renderOverflow(overflowCount) : `+${overflowCount}`}
          </span>
        );

        if (!showTooltip) return overflowItem;

        return (
          <Tooltip>
            <TooltipTrigger render={overflowItem} />
            <TooltipContent>
              {getOverflowTooltipContent
                ? getOverflowTooltipContent(hiddenTokens)
                : getDefaultOverflowTooltipContent()}
            </TooltipContent>
          </Tooltip>
        );
      })()}
    </div>
  );
}

"use client";

import { useMemo, useState, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { getTokenIcon } from "@/lib/onchain/crypto-icons";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";

const sizeClasses = {
  xs: "size-5 text-[9px]",
  sm: "size-6 text-[10px]",
  md: "size-8 text-xs",
  lg: "size-10 text-sm",
  xl: "size-12 text-base",
} as const;

export interface TokenLogoProps {
  /** Token image URL. Always wins over inferred icons */
  src?: string | null;
  /** Token symbol, used for alt text and fallback initials */
  symbol?: string | null;
  /** Token name, used for alt text */
  name?: string | null;
  /** Token contract address, used for icon inference and as a fallback label */
  address?: string | null;
  /** EVM chain id, used with address to infer an icon via the crypto-icons adapter */
  chainId?: number | null;
  /** Visual size. Default: md */
  size?: keyof typeof sizeClasses;
  /** Custom fallback content when the image is missing or fails */
  fallback?: ReactNode;
  /** Show an animated tooltip. Default: false */
  showTooltip?: boolean;
  /** Tooltip content. Defaults to name, symbol, then address. */
  tooltipContent?: ReactNode;
  /** Applied to the root wrapper */
  className?: string;
  /** Applied to the image */
  imageClassName?: string;
  /** Applied to the fallback */
  fallbackClassName?: string;
}

function getFallbackText({
  address,
  name,
  symbol,
}: Pick<TokenLogoProps, "address" | "name" | "symbol">) {
  if (symbol) return symbol.slice(0, 4).toUpperCase();
  if (name) return name.slice(0, 2).toUpperCase();
  if (address) return address.slice(2, 4).toUpperCase();
  return "?";
}

export function TokenLogo({
  src,
  symbol,
  name,
  address,
  chainId,
  size = "md",
  fallback,
  showTooltip = false,
  tooltipContent,
  className,
  imageClassName,
  fallbackClassName,
}: TokenLogoProps) {
  const [failedSrc, setFailedSrc] = useState<string | null>(null);

  // Explicit src wins; otherwise ask the crypto-icons adapter.
  const inferredIcon = useMemo(
    () => (src ? null : getTokenIcon({ chainId, address, symbol })),
    [address, chainId, src, symbol]
  );
  const resolvedSrc =
    src ?? (typeof inferredIcon === "string" ? inferredIcon : null);
  const inferredNode =
    inferredIcon != null && typeof inferredIcon !== "string"
      ? inferredIcon
      : null;
  const shouldShowImage = Boolean(resolvedSrc) && failedSrc !== resolvedSrc;

  const alt = useMemo(() => {
    if (name && symbol) return `${name} (${symbol})`;
    return name ?? symbol ?? address ?? "Token";
  }, [address, name, symbol]);

  const tooltip = tooltipContent ?? name ?? symbol ?? address;

  const logo = (
    <span
      className={cn(
        "relative inline-flex shrink-0 items-center justify-center overflow-hidden rounded-full border bg-muted font-medium text-muted-foreground",
        sizeClasses[size],
        className
      )}
    >
      {shouldShowImage ? (
        <img
          src={resolvedSrc ?? undefined}
          alt={alt}
          className={cn("size-full object-cover", imageClassName)}
          loading="lazy"
          decoding="async"
          referrerPolicy="no-referrer"
          onError={() => setFailedSrc(resolvedSrc)}
        />
      ) : inferredNode ? (
        inferredNode
      ) : (
        <span className={cn("select-none", fallbackClassName)}>
          {fallback ?? getFallbackText({ address, name, symbol })}
        </span>
      )}
    </span>
  );

  if (!showTooltip || tooltip == null) return logo;

  return (
    <Tooltip>
      <TooltipTrigger render={logo} />
      <TooltipContent>{tooltip}</TooltipContent>
    </Tooltip>
  );
}
